queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?price WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasService ?child ; p:hasTravel_Agency ?parent . } GROUP BY ?child }
  ?child p:Price ?price .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Travel_Agency } }
  FILTER(?nf = ?total)
}

